mapper.select:
SELECT 
FROM tasks t
LEFT JOIN users ua ON t.assignee_id = ua.id
LEFT JOIN users uc ON t.creator_id = uc.id


        AND (t.title LIKE CONCAT('%', #{keyword}, '%')
          OR t.description LIKE CONCAT('%', #{keyword}, '%'))


        AND t.status = #{status}


        AND t.assignee_id = #{assigneeId}


        AND t.priority = #{priority}


        AND t.creator_id = #{creatorId}



        AND (t.assignee_id = #{viewerId} OR t.creator_id = #{viewerId})


ORDER BY t.created_at DESC
